-- Création de la classe de Cécile (généré depuis docsmethodes/).
do $$
declare
  v_user uuid;
  v_class uuid;
begin
  select id into v_user from auth.users where email = 'azylis69@hotmail.fr';
  if v_user is null then raise exception 'Utilisateur % introuvable', 'azylis69@hotmail.fr'; end if;

  -- Non destructif : on n'écrit QUE si aucune classe n'existe encore pour ce compte.
  if exists (select 1 from classes where user_id = v_user) then
    raise notice 'Une classe existe deja pour ce compte : aucune insertion.';
    return;
  end if;

    values (v_user, 'custom', '2026-09-01', 'Cécile')
    returning id into v_class;

  -- ── semaines (36) ──




  raise notice 'Classe creee : %', v_class;
end $$;
